def apply_pairs(content, pairs, label='', quiet=False):
    """Apply a list of (old, new) replacements, tracking misses."""
    missed = []
    for old, new in pairs:
        if old not in content:
            missed.append(old)
        content = content.replace(old, new)
    if missed and not quiet:
        for m in missed[:3]:
            print(f'  [MISS] {label}: {m[:80]!r}')
        if len(missed) > 3:
            print(f'  [MISS] {label}: ... and {len(missed)-3} more')
    return content, len(missed)


def is_already_translated(content):
    """Check if the file is already translated to zh-CN."""
    return '<html lang="zh-CN">' in content


def translate_redirect(content):
    """Translate a redirect stub page."""
    pairs = [
        ('<html lang="en">', '<html lang="zh-CN">'),
        ('<title>Redirection</title>', '<title>重定向</title>'),
        ('Redirecting to ', '正在重定向到 '),
    ]
    return apply_pairs(content, pairs, 'redirect')


def translate_generic(content):
    """Apply common UI + text replacements to a generic tokio file."""
    content, _ = apply_pairs(content, COMMON_UI, 'common UI')
    content, _ = apply_pairs(content, COMMON_TEXT, 'common text', quiet=True)
    return content


def find_html_files(root):
    """Walk root and yield HTML file paths, skipping _old and _translate*.py."""
    for dirpath, dirnames, filenames in os.walk(root):
        # Skip _old directories
        dirnames[:] = [d for d in dirnames if d != '_old' and not d.startswith('.')]
        for f in filenames:
            if not f.endswith('.html'):
                continue
            yield os.path.join(dirpath, f)


def main():
    redirect_count = 0
    generic_count = 0
    skipped = 0
    total = 0
    for path in find_html_files(TOKIO_ROOT):
        total += 1
        with open(path, 'r', encoding='utf-8') as f:
            content = f.read()
        if is_already_translated(content):
            # Re-process to apply newly added patterns (replacements are idempotent)
            pass
        if '<title>Redirection</title>' in content:
            new_content, _ = translate_redirect(content)
            redirect_count += 1
        else:
            new_content = translate_generic(content)
            generic_count += 1
        with open(path, 'w', encoding='utf-8') as f:
            f.write(new_content)
    print(f'Total files: {total}')
    print(f'Redirect pages translated: {redirect_count}')
    print(f'Generic files translated: {generic_count}')
    print(f'Skipped (already zh-CN): {skipped}')


if __name__ == '__main__':
    main()
